import { useState } from "react";
import { useNavigate, Link } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import "./Auth.css";

export default function Login() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPwd, setShowPwd] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true); setError("");
    try {
      await login(email, password);
      navigate("/");
    } catch (err) {
      setError(err.response?.data?.message || "Invalid credentials");
    }
    setLoading(false);
  };

  return (
    <div className="auth-page">
      <div className="auth-bg">
        <div className="auth-orb orb1" />
        <div className="auth-orb orb2" />
        <div className="auth-orb orb3" />
        <div className="auth-grid" />
      </div>
      <div className="auth-card">
        <div className="auth-logo-wrap">
          <div className="auth-logo">
            <svg viewBox="0 0 40 40" fill="none" xmlns="http://www.w3.org/2000/svg">
              <circle cx="14" cy="13" r="7" fill="url(#lg1)" />
              <circle cx="26" cy="13" r="7" fill="url(#lg2)" opacity="0.9" />
              <circle cx="20" cy="26" r="7" fill="url(#lg3)" opacity="0.95" />
              <defs>
                <linearGradient id="lg1" x1="0" y1="0" x2="1" y2="1"><stop stopColor="#a78bfa"/><stop offset="1" stopColor="#7c3aed"/></linearGradient>
                <linearGradient id="lg2" x1="0" y1="0" x2="1" y2="1"><stop stopColor="#22d3ee"/><stop offset="1" stopColor="#0891b2"/></linearGradient>
                <linearGradient id="lg3" x1="0" y1="0" x2="1" y2="1"><stop stopColor="#818cf8"/><stop offset="1" stopColor="#06b6d4"/></linearGradient>
              </defs>
            </svg>
          </div>
          <h1 className="auth-brand">PeerSync</h1>
        </div>
        <p className="auth-tagline">Connect. Sync. Belong.</p>
        <h2 className="auth-title">Welcome back</h2>
        <p className="auth-sub">Sign in to continue</p>
        {error && <div className="auth-error">⚠️ {error}</div>}
        <form className="auth-form" onSubmit={handleSubmit}>
          <div className="auth-field">
            <label className="auth-label">EMAIL</label>
            <div className="auth-input-wrap">
              <span className="auth-input-icon">📧</span>
              <input className="auth-input" type="email" placeholder="your@email.com"
                value={email} onChange={e => setEmail(e.target.value)} required />
            </div>
          </div>
          <div className="auth-field">
            <label className="auth-label">PASSWORD</label>
            <div className="auth-input-wrap">
              <span className="auth-input-icon">🔒</span>
              <input className="auth-input" type={showPwd ? "text" : "password"}
                placeholder="Enter your password"
                value={password} onChange={e => setPassword(e.target.value)} required />
              <button type="button" className="auth-eye" onClick={() => setShowPwd(!showPwd)}>
                {showPwd ? "🙈" : "👁️"}
              </button>
            </div>
          </div>
          <button className="auth-btn" type="submit" disabled={loading}>
            {loading ? <span className="auth-spinner" /> : <>Sign In →</>}
          </button>
        </form>
        <p className="auth-switch">Don't have an account? <Link to="/register">Create one</Link></p>
      </div>
    </div>
  );
}
